import scala.collection.mutable.PriorityQueue

def solve(n: Long, edges: Array[Array[Long]]): Long = {
    val adj = Array.fill(n.toInt)(List[(Long, Long, Long)]())
    for (edge <- edges) {
        val u = edge(0).toInt
        val v = edge(1).toInt
        val s = edge(2).toInt
        val e = edge(3).toInt
        adj(u) = adj(u) :+ (v, s, e)
    }
    val dist = Array.fill(n.toInt)(Long.MaxValue)
    dist(0) = 0L
    val pq = PriorityQueue[(Long, Int)]()
    pq += (0L, 0)
    while (pq.nonEmpty) {
        val (currentTime, u) = pq.pop()
        if (u == n.toInt - 1) return currentTime
        if (currentTime > dist(u.toInt)) {
            // skip this state
        } else {
            for (edge <- adj(u.toInt)) {
                val (v, s, e) = edge
                val earliestTime = math.max(currentTime, s)
                if (earliestTime > e) {
                    // skip this edge
                } else {
                    val arrivalTime = earliestTime + 1
                    if (arrivalTime < dist(v.toInt)) {
                        dist(v.toInt) = arrivalTime
                        pq += (arrivalTime, v)
                    }
                }
            }
        }
    }
    -1L
}
